有区别的。 ​ 但是，char argv[]实际上是声明了一个数组argv，该数组保存多个指向char类型的指针。char *argv是声明argv是指向“指向char类型”的指针。前者会声明一个数组，所以会在内存中分配连续的一段空间。例如： 1234567891011121314151617181920#include &lt;stdio.h&gt;int main() &#123; char* strings[] = &#123;&quot;Hatsune&quot;, &quot;Miku&quot;, &quot;!&quot;&#125;; int num_strings = sizeof(strings) / sizeof(strings[0]); for (int i = 0; i &lt; num_strings; i++) &#123; printf(&quot;strings[%d]: %p
&quot;, i, strings[i]); &#125; return 0;&#125;# output:# strings[0]: 0000000000404000# strings[1]: 0000000000404008# strings[2]: 000000000040400D## &amp;strings[0]: 000000000062FDF0# &amp;strings[1]: 000000000062FDF8# &amp;strings[2]: 000000000062FE00 ​ 可以看到，我们打印了出了strings[i]所指向的地址，这是连续的。strings[0]的首地址是4000, 而strings[1]是4008，这是因为strings[0]由7个char（1个字节1个char）组成，然后被程序自己追加了一个\Null以表分割。所以是8个字节。同理，4008+5=400D，也就得到了strings[2]的开头。 ​ 然而，如果我们想用char **argv来办到这点，我们需要用malloc()手动分配空间： 123456789101112131415161718192021222324252627282930313233#include&lt;stdio.h&gt;#include&lt;stdlib.h&gt;#include&lt;string.h&gt;int main() &#123; char **strings = (char **)malloc(sizeof(char *) * 3); strings[0] = (char *)malloc(sizeof(char) * 6); strings[1] = (char *)malloc(sizeof(char) * 6); strings[2] = (char *)malloc(sizeof(char) * 2); strcpy(strings[0], &quot;Hatsune&quot;); strcpy(strings[1], &quot;Miku&quot;); strcpy(strings[2], &quot;!&quot;); for (int i = 0; i &lt; 3; i++) &#123; printf(&quot;strings[%d]: %p
&quot;, i, strings[i]); &#125; printf(&quot;
&quot;); for (int i = 0; i &lt; 3; i++) &#123; printf(&quot;&amp;strings[%d]: %p
